CREATE TABLE signal_index(id BIGINT PRIMARY KEY AUTO_INCREMENT,curve_id VARCHAR(64) NOT NULL,run_no VARCHAR(64) NOT NULL,chamber VARCHAR(8) NOT NULL,channel_code VARCHAR(32) NOT NULL,processing_version VARCHAR(32) NOT NULL,point_count INT NOT NULL,qc_status VARCHAR(16) NOT NULL,checksum CHAR(64) NOT NULL,created_at DATETIME(3) NOT NULL,UNIQUE KEY uk_signal_version(run_no,chamber,channel_code,processing_version),UNIQUE KEY uk_curve_id(curve_id),KEY idx_signal_run(run_no));
